SELECT 'engine_oil' AS item, sku, path FROM products WHERE brand='Mobil' AND series='Mobil All Season Super' AND model='1ZE-TCR' AND name='Engine Oil' AND json_extract(properties,'$.volume')='5000 ml' AND json_extract(properties,'$.viscosity')='10W-40' LIMIT 5;
SELECT 'sealant' AS item, sku, path FROM products WHERE brand='Sika' AND series='Sika Professional' AND model='Sika 28T-UV8' AND name='Sealant' AND json_extract(properties,'$.sealant_type')='silicone sealant' AND json_extract(properties,'$.color_family')='Black' LIMIT 5;
SELECT 'manual_garden_tool' AS item, sku, path FROM products WHERE brand='Gardena' AND series='Gardena Smart PowerMax' AND model='280-5FI' AND name='Manual Garden Tool' AND json_extract(properties,'$.tool_type')='pressure sprayer' LIMIT 5;
SELECT 'safety_eyewear' AS item, sku, path FROM products WHERE brand='3M' AND series='3M Ventilated SecureFit' AND model='2CE-B35' AND name='Safety Eyewear' AND json_extract(properties,'$.lens_color')='Yellow' LIMIT 5;
SELECT 'work_top' AS item, sku, path FROM products WHERE brand='Engelbert Strauss' AND series='Engelbert Strauss e.s.vision' AND model='e.s. 150-ZC6' AND name='Work Top' AND json_extract(properties,'$.garment_type')='polo shirt' LIMIT 5;

