SELECT 'Engelbert Strauss' AS q, sku, path, brand, series, model, name, properties FROM products WHERE brand='Engelbert Strauss' AND model='150-ZC6' LIMIT 50;

SELECT 'Mobil Engine Oil' AS q, sku, path, brand, series, model, name, properties FROM products WHERE brand='Mobil' AND name='Engine Oil' LIMIT 50;
SELECT 'Sika Sealant' AS q, sku, path, brand, series, model, name, properties FROM products WHERE brand='Sika' AND name='Sealant' LIMIT 50;
SELECT 'Gardena Manual Garden Tool' AS q, sku, path, brand, series, model, name, properties FROM products WHERE brand='Gardena' AND name='Manual Garden Tool' LIMIT 50;
SELECT '3M Safety Eyewear' AS q, sku, path, brand, series, model, name, properties FROM products WHERE brand='3M' AND name='Safety Eyewear' LIMIT 50;
