SELECT sku, path, brand, series, model, name, properties FROM products WHERE brand='Sikkens' AND name='Wood Stain and Deck Oil' LIMIT 50;
SELECT sku, path, brand, series, model, name, properties FROM products WHERE brand='Pattex' AND name='Tape and Foam' LIMIT 50;
