SELECT p.sku, p.path, p.brand, p.series, p.model, p.name FROM products p WHERE p.brand='Heco' AND p.series='Heco Zinc Plated' AND p.model='HECO 3DW-64B' AND p.name='Nut Bolt and Washer' AND json_extract(p.properties,'$.fastener_type')='bolt' AND json_extract(p.properties,'$.diameter')='10 mm' LIMIT 10;
SELECT store_id, name, city FROM stores WHERE city='Vienna' ORDER BY store_id;
SELECT i.store_id, i.sku, i.available_today FROM inventory i JOIN stores s ON s.store_id=i.store_id WHERE s.city='Vienna' AND i.sku IN (SELECT sku FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='bolt' AND json_extract(properties,'$.diameter')='10 mm') ORDER BY i.store_id;

SELECT sku, path FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='bolt' AND json_extract(properties,'$.diameter')='10 mm' LIMIT 10;
SELECT id, path, name, city FROM stores WHERE city='Vienna' ORDER BY id;
SELECT s.id, s.name, COALESCE(i.available_today,0) AS available_today
FROM stores s
LEFT JOIN inventory i ON i.store_id=s.id AND i.sku=(SELECT sku FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='bolt' AND json_extract(properties,'$.diameter')='10 mm' LIMIT 1)
WHERE s.city='Vienna'
ORDER BY s.id;
SELECT SUM(COALESCE(i.available_today,0)) AS total_available
FROM stores s
LEFT JOIN inventory i ON i.store_id=s.id AND i.sku=(SELECT sku FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='bolt' AND json_extract(properties,'$.diameter')='10 mm' LIMIT 1)
WHERE s.city='Vienna';

SELECT p.sku, p.path, p.brand, p.series, p.model, p.name, json_extract(p.properties,'$.product_type') AS product_type FROM products p WHERE p.brand='Bondex' AND p.series LIKE '%Bondex Garden Classic%' AND p.model='106-TS1' AND p.name='Wood Stain and Deck Oil' AND lower(json_extract(p.properties,'$.product_type'))='wood stain';

SELECT s.store_id, s.name, s.city FROM stores s WHERE s.city='Graz';

SELECT i.store_id, i.sku, i.available_today FROM inventory i WHERE i.sku IN (SELECT p.sku FROM products p WHERE p.brand='Bondex' AND p.series LIKE '%Bondex Garden Classic%' AND p.model='106-TS1' AND p.name='Wood Stain and Deck Oil' AND lower(json_extract(p.properties,'$.product_type'))='wood stain') AND i.store_id IN (SELECT s.store_id FROM stores s WHERE s.city='Graz');

SELECT id, path, name FROM stores WHERE city='Vienna' ORDER BY id;
SELECT s.id, s.path, s.name, COALESCE(i.available_today,0) AS available_today
FROM stores s
LEFT JOIN inventory i ON i.store_id=s.id AND i.sku='FST-3SJKL8BF'
WHERE s.city='Vienna'
ORDER BY s.id;
SELECT SUM(COALESCE(i.available_today,0)) AS total_available
FROM stores s
LEFT JOIN inventory i ON i.store_id=s.id AND i.sku='FST-3SJKL8BF'
WHERE s.city='Vienna';

SELECT p.sku, p.path FROM products p WHERE p.brand='Bondex' AND p.series LIKE '%Bondex Garden Classic%' AND p.model='106-TS1' AND p.name='Wood Stain and Deck Oil' AND lower(json_extract(p.properties,'$.product_type'))='wood stain' LIMIT 5;

SELECT s.id, s.path, s.name, s.city FROM stores s WHERE s.city='Graz';

SELECT s.id AS store_id, s.path AS store_path, COALESCE(i.available_today,0) AS available_today
FROM stores s
LEFT JOIN inventory i ON i.store_id=s.id AND i.sku IN (
  SELECT p.sku FROM products p
  WHERE p.brand='Bondex' AND p.series LIKE '%Bondex Garden Classic%' AND p.model='106-TS1' AND p.name='Wood Stain and Deck Oil' AND lower(json_extract(p.properties,'$.product_type'))='wood stain'
)
WHERE s.city='Graz';
